import{_ as i,c as l,o as e,a1 as o}from"./chunks/framework.DDNAyvCW.js";const u=JSON.parse('{"title":"快速上手","description":"","frontmatter":{},"headers":[],"relativePath":"docs/mobile/quickstart/index.md","filePath":"docs/mobile/quickstart/index.md"}'),r={name:"docs/mobile/quickstart/index.md"};function t(d,a,c,h,s,n){return e(),l("div",null,a[0]||(a[0]=[o('<h1 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h1><p>本指南将带您完成移动端的安装、登录、添加主机、建立连接和使用 AI 的完整流程。</p><h2 id="第一步-安装应用" tabindex="-1">第一步：安装应用 <a class="header-anchor" href="#第一步-安装应用" aria-label="Permalink to &quot;第一步：安装应用&quot;">​</a></h2><h3 id="ios" tabindex="-1">iOS <a class="header-anchor" href="#ios" aria-label="Permalink to &quot;iOS&quot;">​</a></h3><ol><li>打开 <a href="https://apps.apple.com/cn/app/chaterm/id6753935895" target="_blank" rel="noreferrer">App Store</a></li><li>搜索并安装 Chaterm</li><li>首次启动后按提示完成权限授权</li></ol><h3 id="android" tabindex="-1">Android <a class="header-anchor" href="#android" aria-label="Permalink to &quot;Android&quot;">​</a></h3><ol><li>打开 <a href="/download/">下载页</a> 或在应用商店搜索 Chaterm</li><li>下载最新 Android APK</li><li>安装 APK 文件，并按系统提示允许安装</li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果您希望使用同步能力和完整 AI 功能，建议登录后再开始使用。</p></div><h2 id="第二步-登录账户" tabindex="-1">第二步：登录账户 <a class="header-anchor" href="#第二步-登录账户" aria-label="Permalink to &quot;第二步：登录账户&quot;">​</a></h2><p>Chaterm 移动端支持登录后使用完整能力，也支持先浏览应用再补充登录。</p><ul><li>邮箱验证码登录</li><li>账号密码登录</li><li>第三方登录（以应用当前可用选项为准）</li></ul><h2 id="第三步-添加第一台主机" tabindex="-1">第三步：添加第一台主机 <a class="header-anchor" href="#第三步-添加第一台主机" aria-label="Permalink to &quot;第三步：添加第一台主机&quot;">​</a></h2><ol><li>进入资产页</li><li>进入直接连接然后点击右下角 <code>+</code></li><li>选择“新建”</li><li>填写主机标签、IP、端口、用户名等信息</li><li>选择密码认证或密钥认证</li><li>点击“保存”</li></ol><p>如果您在桌面端开启了数据同步，资产数据会加密同步到移动端。</p><p>更多说明见 <a href="/docs/mobile/assets/">资产管理</a>。</p><h2 id="第四步-建立-ssh-连接" tabindex="-1">第四步：建立 SSH 连接 <a class="header-anchor" href="#第四步-建立-ssh-连接" aria-label="Permalink to &quot;第四步：建立 SSH 连接&quot;">​</a></h2><ol><li>在资产列表中点击目标主机卡片</li><li>应用会自动建立 SSH 连接</li><li>连接成功后进入终端界面</li></ol><p>常用操作：</p><ul><li>点击主机卡片直接连接</li><li>长按卡片可编辑、收藏或删除</li><li>通过搜索快速筛选主机名、IP、用户名和分组</li></ul><h2 id="第五步-开始使用-ai" tabindex="-1">第五步：开始使用 AI <a class="header-anchor" href="#第五步-开始使用-ai" aria-label="Permalink to &quot;第五步：开始使用 AI&quot;">​</a></h2><p>移动端主要提供两种交互方式：</p><ul><li><code>Term</code> 模式：直接执行您输入的命令</li><li><code>Chat</code> 模式：由 AI 理解问题并生成命令或操作建议</li></ul><p>使用步骤：</p><ol><li>进入 AI 对话页</li><li>连接目标主机或选择模型</li><li>在输入框底部切换模式</li><li>输入问题、命令或通过语音发起请求</li><li>查看执行结果或 AI 返回内容</li></ol><p>更多说明见 <a href="/docs/mobile/ai-agent/">AI 对话</a>。</p><h2 id="推荐的首次体验" tabindex="-1">推荐的首次体验 <a class="header-anchor" href="#推荐的首次体验" aria-label="Permalink to &quot;推荐的首次体验&quot;">​</a></h2><ol><li>添加一台测试主机</li><li>发起一次 SSH 连接</li><li>在 <code>Term</code> 模式执行 <code>pwd</code> 或 <code>uname -a</code></li><li>切换到 <code>Chat</code> 模式询问一个 Linux 命令问题</li><li>在个人中心配置主题、语言和 AI 偏好</li></ol>',27)]))}const m=i(r,[["render",t]]);export{u as __pageData,m as default};
